func Test_AllMessageTypes(t *testing.T) {
	// Request with all message role types (system, user, assistant, tool) to verify round-trip serialization
	var request pkg.ChatCompletionRequest
	if err := json.Unmarshal([]byte(`{"messages":[{"content":"You are a helpful assistant.","role":"system"},{"content":"What is the weather in Paris?","role":"user"},{"content":null,"role":"assistant","tool_calls":[{"function":{"arguments":"{\"location\": \"Paris, France\"}","name":"get_weather"},"id":"call_xyz789","type":"function"}]},{"content":"{\"temperature\": 18, \"unit\": \"celsius\", \"description\": \"Partly cloudy\"}","role":"tool","tool_call_id":"call_xyz789"}],"model":"gpt-4"}`), &request); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	mockURL := os.Getenv("MOCK_SERVER_URL") + "/fixtures/all_message_types"
	client, clientErr := pkg.CreateClient("test-key", &mockURL, nil, nil, nil)
	if clientErr != nil {
		t.Fatalf("create client failed: %v", clientErr)
	}
	result, err := client.Chat(request)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	var choices0FinishReason string
	if result.Choices[0].FinishReason != nil {
		choices0FinishReason = string(*result.Choices[0].FinishReason)
	}
	assert.Equal(t, len(result.Choices), 1, "expected exactly 1 elements")
	if strings.TrimSpace(string(choices0FinishReason)) != `stop` {
		t.Errorf("equals mismatch: got %v", choices0FinishReason)
	}
}

